// TinyTapeout DTL Safety Gate — FSM Variant
// Generated by ChipGate TinyTapeoutPrep
// Public demonstration design only.
// Does not prove silicon correctness or physical safety.

module tiny_dtl_gate_fsm (
    input  wire ai_output,
    input  wire verifier_ok,
    input  wire policy_ok,
    input  wire sensor_ok,
    input  wire timeout,
    input  wire kill_switch,
    input  wire reset,
    output reg  actuator_enable,
    output reg  blocked,
    output reg  failsafe,
    output reg  approved,
    output reg  evidence_pulse
);

    // FSM state encoding
    localparam S_IDLE     = 3'd0;
    localparam S_PROPOSED = 3'd1;
    localparam S_VERIFYING = 3'd2;
    localparam S_APPROVED = 3'd3;
    localparam S_BLOCKED  = 3'd4;
    localparam S_FAILSAFE = 3'd5;

    reg [2:0] state;

    // State transition
    always @(*) begin
        case (state)
            S_IDLE: begin
                if (reset)
                    state = S_IDLE;
                else if (kill_switch || timeout)
                    state = S_FAILSAFE;
                else if (ai_output)
                    state = S_PROPOSED;
                else
                    state = S_IDLE;
            end
            S_PROPOSED: begin
                if (reset)
                    state = S_IDLE;
                else if (kill_switch || timeout)
                    state = S_FAILSAFE;
                else if (verifier_ok && policy_ok && sensor_ok)
                    state = S_VERIFYING;
                else if (!verifier_ok || !policy_ok || !sensor_ok)
                    state = S_BLOCKED;
                else
                    state = S_PROPOSED;
            end
            S_VERIFYING: begin
                if (reset)
                    state = S_IDLE;
                else if (kill_switch || timeout)
                    state = S_FAILSAFE;
                else if (verifier_ok && policy_ok && sensor_ok)
                    state = S_APPROVED;
                else
                    state = S_BLOCKED;
            end
            S_APPROVED: begin
                if (reset || kill_switch || timeout
                    || !verifier_ok || !policy_ok || !sensor_ok)
                    state = S_FAILSAFE;
                else
                    state = S_APPROVED;
            end
            S_BLOCKED: begin
                if (reset)
                    state = S_IDLE;
                else if (kill_switch || timeout)
                    state = S_FAILSAFE;
                else
                    state = S_BLOCKED;
            end
            S_FAILSAFE: begin
                if (reset)
                    state = S_IDLE;
                else
                    state = S_FAILSAFE;
            end
            default: state = S_IDLE;
        endcase
    end

    // Output logic
    always @(*) begin
        actuator_enable = 1'b0;
        blocked = 1'b0;
        failsafe = 1'b0;
        approved = 1'b0;
        evidence_pulse = 1'b0;
        case (state)
            S_IDLE: begin
                failsafe = 1'b1;
            end
            S_PROPOSED: begin
                blocked = 1'b1;
            end
            S_VERIFYING: begin
                blocked = 1'b1;
            end
            S_APPROVED: begin
                actuator_enable = 1'b1;
                approved = 1'b1;
                evidence_pulse = 1'b1;
            end
            S_BLOCKED: begin
                blocked = 1'b1;
            end
            S_FAILSAFE: begin
                failsafe = 1'b1;
            end
        endcase
    end

endmodule